var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"하아. 고작 일반인 한 명 살리는 데 시간이 이렇게 걸리다니......","JPN":"はあ、一般人1人を蘇生するのにこんなに時間がかかるなんて……","ENG":"Ugh... I can't believe it's taking me this long to keep a non-Counter alive...","TWN":"哈啊，沒想到救活一個普通人花了這麼長的時間……"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"나도 이제 갈 때가 다 됐나 봐.","JPN":"私の腕もずいぶん衰えてしまったみたいね。","ENG":"I think it's time I retired.","TWN":"看來我也不行了。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"그, 그렇지 않습니다, 교수님.","JPN":"そ、そんなことないですよ、教授。","ENG":"Oh no, ma'am.","TWN":"不、不是的，教授。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"교수님의 실력은 언제나 최고의 자리에서 빛나고 계십니다. 암요.","JPN":"教授の実力は常に一流を超えて、輝いていらっしゃいますよ。ええ、そうです。","ENG":"You're still the best, as always. Everybody knows that.","TWN":"您的實力向來一直是最棒的，毋庸置疑。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"역시 그렇지?","JPN":"やっぱりそうだよね？","ENG":"I know, right?","TWN":"是吧？"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"그런 의미에서 제자야, 약국에 가서 노화방지 비타민 열 박스만 사다 줄래?","JPN":"そんなわけで我が助手、ドラッグストアに行って栄養ドリンクを10箱くらい買ってきてくれない？","ENG":"Then would you be so kind to get me a dozen boxes of anti-aging vitamins at the pharmacy?","TWN":"既然如此，我親愛的徒弟啊，你能去藥店幫我買十盒抗衰老的維生素嗎？"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"아...... 네......","JPN":"あ……はい……","ENG":"Oh... Okay...","TWN":"啊……好吧……"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......상태는 어떻죠?","JPN":"……具合はどうですか？","ENG":"How's she doing?","TWN":"……她怎麼樣？"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"제가 도착했을 때는 당장 죽어도 이상하지 않을 정도였는데.","JPN":"私が着いた時はすぐに死んでもおかしくない状態でした。","ENG":"When I found her, she was right about to kick the bucket.","TWN":"我到達的時候，她已經瀕臨死亡了。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"후훗. 이 정도도 못하면 초 천재라고 말할 수도 없죠.","JPN":"フフッ、これくらいの傷も治せないなら、超天才は名乗れませんよ。","ENG":"Heh, they don't call me a super genius for nothing.","TWN":"呼呼，如果救不活，那我就妄稱超級天才了。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"그리고 제게도 조금은 유익한 시간이었어요.","JPN":"あと、私にとっても少しは有意義な時間でした。","ENG":"Actually, this was a bit of a learning experience for me, too.","TWN":"而且對我來說，是非常有意義的時間。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"그 환자, 일반인인 주제에 꽤나 흥미로운 연구소재가 될 것 같거든요.","JPN":"あの患者、一般人のくせにかなり興味深い研究素材になりそうです。","ENG":"The patient will make a rather interesting research subject... for a non-Counter, that is.","TWN":"那個患者明明是個普通人，但卻是一個非常有趣的研究素材。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"무슨 소리죠? 교수님은 카운터 외엔 거들떠도 안 보잖아요?","JPN":"どういう意味ですか？　教授はカウンター以外には全く興味ないのでは？","ENG":"Seriously? I thought you didn't give a single glance to anyone who's not a Counter.","TWN":"您這是什麼意思？您不是對制裁者以外的人都不理睬的嗎？"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"어머. 거울 속의 나는 자주 보는데.","JPN":"あら、鏡の中の自分には興味津々ですよ。","ENG":"Oh no. I look at myself all the time in the mirror.","TWN":"哪有，我可是經常看鏡子裡的我呢。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"자, 수술 도중에 그 베로니카란 환자에게서 채취한 물질의 화학식이에요.","JPN":"さて、これがベロニカという患者さんから手術中に採取した物質の化学式です。","ENG":"Now, this is the chemical formula of the substance I extracted from Veronica during the surgery.","TWN":"你看，這是我在手術的時候從貝洛妮卡身上提取的物質的化學公式。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L24_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"뭔지 알아 보겠어요?","JPN":"何なのか分かりますか？","ENG":"Do you recognize it?","TWN":"知道這是什麼嗎？"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"전 교수님처럼 공부로 먹고 사는 사람이 아니에요. 무슨 물질이죠?","JPN":"私は教授みたいに研究で食べていく人間ではないので。どんな物質ですか？","ENG":"No, I never paid attention in chemistry class. What is that?","TWN":"我又不是教授您這樣的學者。這到底是什麼物質？"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"자세히 알고 싶으면 정밀 조사가 필요하겠지만, 제가 봤을 때 이건 식물에서 추출한 독을 이용해 만든 신경 세포 조작 물질이에요.","JPN":"詳しく知るには精密調査が必要ですが、おそらくこれは植物から抽出した毒で作った神経細胞操作物質です。","ENG":"I'll need to analyze it more closely to verify the details, but from what I can tell, this is a substance derived from a poisonous plant that can manipulate neurons.","TWN":"具體的還需要做更精密的檢查，但在我看來這是用從植物裡提取的毒液製作的神經細胞操控物質。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"신경 세포......?","JPN":"神経細胞……？","ENG":"Neurons? You mean nerve cells?","TWN":"神經細胞……？"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"네. 아주 우아한 방식으로 조합했더군요.","JPN":"はい。とても優雅な方法で組み合わせたようです。","ENG":"Yes. It was concocted in a most sophisticated fashion.","TWN":"是的，而且還是用非常優雅的方式組合起來的。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"대체 누가 만들었는지 얼굴 한 번 보고 싶어질 만큼.","JPN":"いったいどんな人物が作ったのか、顔を見てみたいぐらいです。","ENG":"I would like to meet whoever designed it.","TWN":"我真想看看做這東西的人到底長什麼樣子。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"참, 그러고 보니 대정화 전쟁 때도 비슷한 시도가 있었다는 논문을 읽은 적이 있는데.","JPN":"そういえば、大浄化戦争の時に似たような試みがあったという論文を読んだことありますね。","ENG":"Oh, I just remembered reading a paper that argued a similar attempt was made during the Grand Purification War.","TWN":"對了，我之前讀過一篇論文，裡面有大淨化戰爭時期有人嘗試做出這種物質的內容。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"그럼 이 물질을 사람에게 투여하면 어떻게 되죠?","JPN":"その物質を人間に投与するとどうなるんですか？","ENG":"So what happens if you inject a person with this?","TWN":"如果把這個物質注入到人體會怎麼樣？"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"간단하게 말하면 인위적으로 무통증 증상을 만들 수 있어요.","JPN":"簡単に言うと、人為的に無痛症を発症させることができます。","ENG":"The short version is that you can artificially prevent the person from feeling any pain.","TWN":"簡單來說，可以人為造出無痛症狀。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"추위도, 더위도 타지 않고 총을 맞거나 죽기 직전의 중상을 입어도 아무렇지 않죠.","JPN":"寒さも暑さも感じることなく、撃たれたり死ぬ寸前の重傷を負っても平気でしょう。","ENG":"They don't feel cold or hot. Even if they get shot or fatally wounded, they don't feel a thing.","TWN":"不怕冷，也不怕熱，即使被槍擊中或者受到重傷而即將死亡也不會有任何感覺。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"애초에 뇌가 감각을 인지하는 기능이 고장나 있는 상태니까요.","JPN":"脳の感覚を認知する機能が故障している状態ですからね。","ENG":"With this in their system, their brain's ability to sense anything is completely out of order.","TWN":"因為大腦喪失了認知感覺的功能。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"하지만...... 그러면 오히려 더 위험하지 않나요? 자기가 다친 줄도 모를 거 아니에요?","JPN":"でも……それだとむしろ危ないんじゃないでしょうか。自分が怪我したことに気付けないのでは？","ENG":"But isn't that too dangerous? The person wouldn't even know if they got hurt.","TWN":"可是……那豈不是更危險？連自己受傷都不知道？"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"맞아요. 일상에서도 행동 하나하나를 조신하게 해야죠.","JPN":"そうです。なので日常的な行動でも慎重にならなきゃいけないでしょうね。","ENG":"That's right. It would require the recipient to exercise extreme caution, even in daily life.","TWN":"是的，因此在日常生活中一舉一動都會小心翼翼。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"바로 치료하면 문제없을 작은 상처도 크게 악화될 수 있거든요.","JPN":"すぐ治療すれば問題ないような小さい傷が悪化することもありますから。","ENG":"Even the most trivial wounds could fester dangerously in a state like this.","TWN":"本沒有任何問題的小傷口，最後也會嚴重惡化。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"그런데도 이런 물질이 몸 속에서 발견되었다는 건 이유가 뻔하죠.","JPN":"そんな物質が体内で発見される理由はハッキリしていると思います。","ENG":"So the fact that this substance was found in the patient tells me one thing.","TWN":"她身上有這種東西，其原因可想而知。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"그 환자, 제 생각엔 한 번 쓰고 버려도 상관없는 소모품으로 취급 받았던 것 같아요.","JPN":"あの患者、おそらく使い捨ての消耗品として扱われていたのでしょう。","ENG":"Whoever injected her with this stuff seems to have treated her as an expendable instrument.","TWN":"我想應該是有人把她當成了消耗品，用過一次就可以扔掉的那種。"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"이래서 카운터가 좋다니까요. 이런 짓 안 해도 잘만 싸울 수 있잖아요. 안 그래요?","JPN":"だから一般人よりカウンターの方が好きなんです。こんなことしなくても戦えるから。そう思いません？","ENG":"This is why I prefer Counters. They can fight just fine without resorting to dirty tricks like this, am I right?","TWN":"所以還是制裁者比較好啊，不用如此也有很高的戰鬥力，是不是？"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"교, 교수님......! 큰일이에요!","JPN":"きょ、教授……！　大変です！","ENG":"P-Professor! It's an emergency!","TWN":"教、教授……！大事不好了！"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"왜 그러니, 조교야? 설마 비타민 다 떨어졌니?","JPN":"どうしたの？　まさか栄養ドリンクが売り切れだったの？","ENG":"What's wrong? Are they out of vitamins?","TWN":"怎麼了，助教？維生素沒買到？"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"그게...... 방금 병동에서 연락이 왔는데 환자가......","JPN":"それが……さっき病棟から連絡が来て、患者さんが……","ENG":"No... I just got word from the infirmary ward...","TWN":"那個……剛剛病房那邊說，患者……"},"stage":{"bg":"LABORATORY","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"사라졌다고...... ","JPN":"消えた、と…… ","ENG":"The patient disappeared... ","TWN":"不見了……"},"stage":{"bg":"FALL_PARK","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};